package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Type;
import java.util.HashMap;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class MapTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor constructorConstructor;

  @Mock
  private Gson gson;

  @Mock
  private ObjectConstructor<HashMap<String, String>> objectConstructor;

  @Mock
  private TypeAdapter<String> keyAdapter;

  @Mock
  private TypeAdapter<String> valueAdapter;

  private MapTypeAdapterFactory factory;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    factory = new MapTypeAdapterFactory(constructorConstructor, true);
  }

  @Test
  void create_withNonMapType_returnsNull() {
    TypeToken<String> stringTypeToken = TypeToken.get(String.class);
    TypeAdapter<String> adapter = factory.create(gson, stringTypeToken);
    assertNull(adapter);
  }

  @Test
  void create_withMapType_returnsAdapter() {
    TypeToken<HashMap<String, String>> typeToken = new TypeToken<HashMap<String, String>>() {};
    Type keyType = String.class;
    Type valueType = String.class;

    // Mock static method $Gson$Types.getMapKeyAndValueTypes(Type, Class)
    // Since static mocking is not available here, we simulate by using real method indirectly
    // But for simplicity, we recreate the behavior manually

    // Mock getKeyAdapter to return keyAdapter
    MapTypeAdapterFactory spyFactory = spy(factory);
    doReturn(keyAdapter).when(spyFactory).getKeyAdapter(eq(gson), eq(keyType));
    when(gson.getAdapter(TypeToken.get(valueType))).thenReturn(valueAdapter);
    when(constructorConstructor.get(typeToken)).thenReturn(objectConstructor);

    TypeAdapter<HashMap<String, String>> adapter = spyFactory.create(gson, typeToken);

    assertNotNull(adapter);
    assertEquals(MapTypeAdapterFactory.Adapter.class, adapter.getClass());

    // Verify interactions
    verify(spyFactory).getKeyAdapter(gson, keyType);
    verify(gson).getAdapter(TypeToken.get(valueType));
    verify(constructorConstructor).get(typeToken);
  }
}
